python3 -c "import os,sys,subprocess,json as j,time,uuid
base=os.environ.get('FORSETI_BASE_URL','http://localhost')
token=os.environ.get('TELEMETRY_TOKEN','')
admin_cookie=os.environ.get('FORSETI_COOKIE_ADMIN','')
drupal_root=os.environ.get('DRUPAL_ROOT','/home/ubuntu/forseti.life/sites/forseti')
if not token:
  print('SKIP: TELEMETRY_TOKEN not set; happy-path requires valid token')
  sys.exit(0)
api=base+'/api/copilot-agent-tracker/event'
tok_header='X-Copilot-Agent-Tracker-Token: '+token
agent_id='qa-hp-'+str(uuid.uuid4())[:8]
def post(payload):
  r=subprocess.run(['curl','--max-time','10','-s','-w','\n%{http_code}','-X','POST','-H','Content-Type: application/json','-H',tok_header,'-d',j.dumps(payload),api],capture_output=True,text=True)
  lines=r.stdout.strip().split('\n'); code=lines[-1]; body='\n'.join(lines[:-1])
  return code,body
def drush_count(table,field,value):
  expr=f\"echo \\\\Drupal::database()->select('{table}','t')->condition('{field}','{value}')->countQuery()->execute()->fetchField();\"
  r=subprocess.run(['/usr/local/bin/drush','--root='+drupal_root,'php:eval',expr],capture_output=True,text=True)
  try: return int(r.stdout.strip())
  except: return -1
failures=[]
code,body=post({'agent_id':agent_id,'status':'active','current_action':'initial-test'})
print('AC-HP-01 first POST:',code)
if code=='200':
  cnt=drush_count('copilot_agent_tracker_agents','agent_id',agent_id)
  print('  agent row count:',cnt)
  if cnt!=1: failures.append('AC-HP-01 FAIL: agent row count='+str(cnt)+', want 1')
  else: print('  AC-HP-01 PASS')
else: print('AC-HP-01: NOTE POST returned',code,'(module may not be implemented); skipping DB checks')
if code=='200':
  code2,_=post({'agent_id':agent_id,'status':'active','current_action':'upsert-check'})
  print('AC-HP-02 second POST:',code2)
  cnt2=drush_count('copilot_agent_tracker_agents','agent_id',agent_id)
  print('  agent row count after upsert:',cnt2)
  if cnt2!=1: failures.append('AC-HP-02 FAIL: row count='+str(cnt2)+' after upsert, want 1')
  else: print('  AC-HP-02 PASS: upsert kept 1 row')
if code=='200' and admin_cookie:
  r=subprocess.run(['curl','--max-time','10','-s','-H','Cookie: '+admin_cookie,base+'/admin/reports/copilot-agent-tracker'],capture_output=True,text=True)
  if agent_id in r.stdout: print('AC-HP-03 PASS: agent_id in dashboard')
  else: failures.append('AC-HP-03 FAIL: agent_id not found in dashboard response')
else: print('AC-HP-03: SKIP - no admin cookie or POST failed')
[print(f,file=sys.stderr) for f in failures]
sys.exit(1 if failures else 0)
"

python3 -c "import os,sys,subprocess,json as j
base=os.environ.get('FORSETI_BASE_URL','http://localhost')
token=os.environ.get('TELEMETRY_TOKEN','')
admin_cookie=os.environ.get('FORSETI_COOKIE_ADMIN','')
auth_cookie=os.environ.get('FORSETI_COOKIE_AUTHENTICATED','')
drupal_root=os.environ.get('DRUPAL_ROOT','/home/ubuntu/forseti.life/sites/forseti')
api=base+'/api/copilot-agent-tracker/event'
tok_header='X-Copilot-Agent-Tracker-Token: '+token if token else ''
def curl_code(url,cookie='',method='GET',body=None,extra_headers=None):
  cmd=['curl','--max-time','10','-o','/dev/null','-w','%{http_code}','-s','-X',method]
  if cookie: cmd+=['-H','Cookie: '+cookie]
  if body: cmd+=['-H','Content-Type: application/json','-d',j.dumps(body)]
  for h in (extra_headers or []): cmd+=['-H',h]
  cmd.append(url)
  return subprocess.run(cmd,capture_output=True,text=True).stdout.strip()
failures=[]
if auth_cookie:
  c=curl_code(base+'/admin/reports/copilot-agent-tracker',cookie=auth_cookie)
  print('AC-SEC-01 auth-no-perm:',c)
  if c!='403': failures.append('AC-SEC-01 FAIL: got '+c+', want 403 (unauthorized access)')
  else: print('  AC-SEC-01 PASS')
else: print('AC-SEC-01: SKIP - FORSETI_COOKIE_AUTHENTICATED not set')
print('AC-SEC-02: agent tracker dashboard is read-only; no admin-side POST state-changing routes. CSRF requirement passes vacuously per spec (OQ-1). Telemetry API uses token-auth (not Drupal CSRF).')
if token:
  long_id='A'*80
  c=curl_code(api,method='POST',body={'agent_id':long_id,'status':'active','current_action':'sec-test'},extra_headers=[tok_header])
  print('AC-SEC-03 oversized agent_id (80 chars):',c)
  if c not in ('400','422'): failures.append('AC-SEC-03 FAIL: oversized agent_id got '+c+', want 400/422')
  else: print('  AC-SEC-03a PASS')
  xss_id='<script>alert(1)</script>'
  r=subprocess.run(['curl','--max-time','10','-s','-X','POST','-H','Content-Type: application/json','-H',tok_header,'-d',j.dumps({'agent_id':xss_id,'status':'active','current_action':'xss-test'}),api],capture_output=True,text=True)
  lines=r.stdout.strip().split('\n'); post_code=lines[-1]; post_body_txt='\n'.join(lines[:-1])
  if post_code in ('400','422'): print('  AC-SEC-03b PASS: XSS agent_id rejected at API')
  elif post_code=='200' and admin_cookie:
    dr=subprocess.run(['curl','--max-time','10','-s','-H','Cookie: '+admin_cookie,base+'/admin/reports/copilot-agent-tracker'],capture_output=True,text=True)
    if '<script>alert(1)</script>' in dr.stdout: failures.append('AC-SEC-03b FAIL: unescaped XSS in dashboard')
    else: print('  AC-SEC-03b PASS: XSS payload stored but HTML-escaped in dashboard')
  else: print('  AC-SEC-03b: NOTE post_code=',post_code,'admin_cookie set=',bool(admin_cookie))
else: print('AC-SEC-03: SKIP - TELEMETRY_TOKEN not set')
if token:
  r=subprocess.run(['/usr/local/bin/drush','--root='+drupal_root,'watchdog:show','--count=20','--type=copilot_agent_tracker','--format=json'],capture_output=True,text=True)
  try:
    rows=j.loads(r.stdout) if r.stdout.strip() else []
    pii_fields=['chat_log','transcript','credential','password','secret']
    leaked=[f for f in pii_fields if any(f in str(row).lower() for row in rows)]
    if leaked: failures.append('AC-SEC-04 FAIL: PII fields in watchdog: '+str(leaked))
    else: print('AC-SEC-04 PASS: no PII fields in watchdog (rows checked:',len(rows),')')
  except Exception as e: print('AC-SEC-04: NOTE could not parse drush output:',str(e)[:80])
else: print('AC-SEC-04: SKIP - TELEMETRY_TOKEN not set')
[print(f,file=sys.stderr) for f in failures]
sys.exit(1 if failures else 0)
"
